/* Core application, map, filters, editing, calibration and backup logic. */
const CATEGORIES=["Buried Treasure","Normal Chest","Hidden Chest","Mayan Stela","Elite Ship Plan","Diving Location","Templar Hunt","Fort","Legendary Ship","Animus Fragment","Sea Shanty"];
const VERIFICATIONS=["Resynced verified","Legacy location — needs Resynced confirmation","Community reported"];
const symbols={"Buried Treasure":"💰","Normal Chest":"▣","Hidden Chest":"✦","Mayan Stela":"◆","Elite Ship Plan":"📜","Diving Location":"≈","Templar Hunt":"◎","Fort":"♜","Legendary Ship":"⛵","Animus Fragment":"⬡","Sea Shanty":"♪"};
const blankState=()=>({locations:structuredClone(EMBEDDED_LOCATIONS),calibration:[],corrections:[],settings:{categories:[...CATEGORIES],verifiedOnly:false,hideCompleted:false,favoritesOnly:false}});
let state=loadState();
let selectedID=null,editingID=null,correctionID=null,pendingCalibration=null;
let transform={scale:1,tx:0,ty:0}, pointers=new Map(),lastDistance=0,dragStart=null;
let markerEdit=false,calibrationMode=false;

function loadState(){try{const parsed=JSON.parse(localStorage.getItem(STORAGE_KEY));return parsed&&parsed.locations?parsed:blankState()}catch{return blankState()}}
function saveState(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state))}
function esc(s=''){return String(s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function statusClass(v){return v==="Resynced verified"?'verified':v.startsWith('Legacy')?'legacy':'community'}
function openModal(id){document.getElementById(id).classList.add('open')}
function closeModal(id){document.getElementById(id).classList.remove('open')}
document.querySelectorAll('[data-close]').forEach(b=>b.addEventListener('click',()=>closeModal(b.dataset.close)));
document.querySelectorAll('.modal').forEach(m=>m.addEventListener('click',e=>{if(e.target===m)closeModal(m.id)}));

function renderChips(){
 const el=document.getElementById('categoryChips');el.innerHTML='';
 CATEGORIES.forEach(c=>{const b=document.createElement('button');b.className='chip '+(state.settings.categories.includes(c)?'active':'');b.textContent=c;b.addEventListener('click',()=>{const a=state.settings.categories;a.includes(c)?a.splice(a.indexOf(c),1):a.push(c);saveState();renderAll()});el.appendChild(b)})
 ['verifiedOnly','hideCompleted','favoritesOnly'].forEach(id=>document.getElementById(id).classList.toggle('active',state.settings[id]));
}
function filteredLocations(){
 const q=document.getElementById('search').value.trim().toLowerCase();
 return state.locations.filter(i=>state.settings.categories.includes(i.category)&&(!state.settings.verifiedOnly||i.verification==="Resynced verified")&&(!state.settings.hideCompleted||!i.completed)&&(!state.settings.favoritesOnly||i.favorite)&&(!q||`${i.name} ${i.region} ${i.reward} ${i.gameX},${i.gameY}`.toLowerCase().includes(q)));
}
function converter(gameX,gameY){
 if(state.calibration.length<2)return{x:gameX/1000,y:1-gameY/1000};
 const [a,b]=state.calibration;
 const sx=(b.imageX-a.imageX)/((b.gameX-a.gameX)||.0001);
 const sy=(b.imageY-a.imageY)/((b.gameY-a.gameY)||.0001);
 return{x:a.imageX+(gameX-a.gameX)*sx,y:a.imageY+(gameY-a.gameY)*sy};
}
function inverseConverter(imageX,imageY){
 if(state.calibration.length<2)return{x:imageX*1000,y:(1-imageY)*1000};
 const [a,b]=state.calibration;
 const sx=(b.gameX-a.gameX)/((b.imageX-a.imageX)||.0001);
 const sy=(b.gameY-a.gameY)/((b.imageY-a.imageY)||.0001);
 return{x:a.gameX+(imageX-a.imageX)*sx,y:a.gameY+(imageY-a.imageY)*sy};
}
function positionFor(i){return i.customImageX!=null&&i.customImageY!=null?{x:i.customImageX,y:i.customImageY}:converter(i.gameX,i.gameY)}
function clusters(items){
 const step=transform.scale<1.8?.065:.027,b=new Map();
 items.forEach(i=>{const p=positionFor(i),k=`${Math.floor(p.x/step)}-${Math.floor(p.y/step)}`;if(!b.has(k))b.set(k,{items:[],x:p.x,y:p.y});b.get(k).items.push(i)});
 return [...b.values()];
}
function renderMap(){
 const layer=document.getElementById('markerLayer');layer.innerHTML='';
 clusters(filteredLocations()).forEach(group=>{
   const btn=document.createElement('button');btn.className='marker';
   btn.style.left=(group.x*100)+'%';btn.style.top=(group.y*100)+'%';
   if(group.items.length>1&&!markerEdit){btn.classList.add('cluster');btn.innerHTML=`<span class="marker-dot">${group.items.length}</span>`;btn.addEventListener('click',()=>{zoomAt(group.x,group.y,1.6)})}
   else{
     const i=group.items[0];btn.dataset.id=i.id;btn.classList.add(statusClass(i.verification));if(i.completed)btn.classList.add('completed');
     btn.innerHTML=`<span class="marker-dot">${symbols[i.category]||'•'}</span>`;
     btn.setAttribute('aria-label',`${i.name}, ${i.verification}`);
     btn.addEventListener('click',e=>{e.stopPropagation();if(!markerEdit)showDetail(i.id)});
     if(markerEdit){
       btn.addEventListener('pointerdown',e=>{e.stopPropagation();btn.setPointerCapture(e.pointerId);btn._drag=true});
       btn.addEventListener('pointermove',e=>{if(!btn._drag)return;const rect=document.getElementById('viewport').getBoundingClientRect();const x=(e.clientX-rect.left-transform.tx)/(rect.width*transform.scale);const y=(e.clientY-rect.top-transform.ty)/(rect.height*transform.scale);i.customImageX=Math.min(1,Math.max(0,x));i.customImageY=Math.min(1,Math.max(0,y));const g=inverseConverter(i.customImageX,i.customImageY);i.gameX=Math.round(g.x);i.gameY=Math.round(g.y);btn.style.left=(i.customImageX*100)+'%';btn.style.top=(i.customImageY*100)+'%';document.getElementById('coordReadout').textContent=`${i.name}: ${i.gameX}, ${i.gameY}`});
       btn.addEventListener('pointerup',()=>{btn._drag=false;saveState();renderAll()});
     }
   }
   layer.appendChild(btn);
 });
}
function renderList(){
 const el=document.getElementById('locationList');el.innerHTML='';
 filteredLocations().forEach(i=>{const b=document.createElement('button');b.className='location-row'+(selectedID===i.id?' selected':'');b.innerHTML=`<strong>${esc(i.name)} ${i.favorite?'★':''} ${i.completed?'✓':''}</strong><small>${esc(i.region)} • (${Math.round(i.gameX)}, ${Math.round(i.gameY)}) • ${esc(i.category)}</small><span class="status ${statusClass(i.verification)}">${esc(i.verification)}</span>${i.isAggregate?'<span class="status legacy">Aggregate marker</span>':''}`;b.addEventListener('click',()=>showDetail(i.id));el.appendChild(b)})
}
function showDetail(id){
 selectedID=id;const i=state.locations.find(x=>x.id===id);if(!i)return;
 document.getElementById('detailTitle').textContent=i.name;
 document.getElementById('coordReadout').textContent=`${i.name}: ${Math.round(i.gameX)}, ${Math.round(i.gameY)}`;
 const warning=i.verification!=="Resynced verified"?`<div class="warning">${i.verification.startsWith('Legacy')?'This record is based on original-game data and may differ in Resynced.':'This is community-reported and should be confirmed.'}</div>`:'';
 const img=i.photoData?`<img class="detail-image" src="${i.photoData}" alt="User reference screenshot for ${esc(i.name)}">`:'';
 document.getElementById('detailBody').innerHTML=`${img}${warning}
 <div class="info-grid" style="margin-top:12px"><b>Category</b><span>${esc(i.category)}</span><b>Region</b><span>${esc(i.region)}</span><b>Coordinates</b><span>${Math.round(i.gameX)}, ${Math.round(i.gameY)}</span><b>Reward</b><span>${esc(i.reward)}</span><b>Requires</b><span>${esc(i.prerequisite)}</span><b>Directions</b><span>${esc(i.instructions)}</span><b>Source</b><span>${esc(i.sourceTitle||'Not entered')}</span></div>
 <label style="display:block;margin-top:12px">Personal notes<textarea id="detailNotes">${esc(i.notes||'')}</textarea></label>
 <div class="action-row" style="margin-top:12px">
  <button id="toggleComplete" class="primary">${i.completed?'Mark incomplete':'Mark complete'}</button>
  <button id="toggleFavorite" class="secondary">${i.favorite?'Remove favorite':'Add favorite'}</button>
  <button id="editSelected" class="secondary">Edit</button>
  <button id="reportSelected" class="secondary">Report correction</button>
  <button id="focusSelected" class="secondary">Zoom to marker</button>
 </div>`;
 document.getElementById('detailNotes').addEventListener('input',e=>{i.notes=e.target.value;saveState()});
 document.getElementById('toggleComplete').addEventListener('click',()=>{i.completed=!i.completed;saveState();closeModal('detailModal');renderAll()});
 document.getElementById('toggleFavorite').addEventListener('click',()=>{i.favorite=!i.favorite;saveState();closeModal('detailModal');renderAll()});
 document.getElementById('editSelected').addEventListener('click',()=>{closeModal('detailModal');openEditor(i.id)});
 document.getElementById('reportSelected').addEventListener('click',()=>{closeModal('detailModal');openCorrection(i.id)});
 document.getElementById('focusSelected').addEventListener('click',()=>{closeModal('detailModal');const p=positionFor(i);zoomAt(p.x,p.y,2.3)});
 openModal('detailModal');renderList();
}
function zoomAt(x,y,target){
 const vp=document.getElementById('viewport').getBoundingClientRect();transform.scale=Math.min(6,Math.max(1,target));transform.tx=vp.width/2-x*vp.width*transform.scale;transform.ty=vp.height/2-y*vp.height*transform.scale;applyTransform();renderMap()
}
function applyTransform(){document.getElementById('stage').style.transform=`translate(${transform.tx}px,${transform.ty}px) scale(${transform.scale})`}
function zoom(f){const vp=document.getElementById('viewport').getBoundingClientRect(),cx=vp.width/2,cy=vp.height/2,old=transform.scale;transform.scale=Math.min(6,Math.max(1,old*f));transform.tx=cx-(cx-transform.tx)*(transform.scale/old);transform.ty=cy-(cy-transform.ty)*(transform.scale/old);applyTransform();renderMap()}
function resetMap(){transform={scale:1,tx:0,ty:0};applyTransform();renderMap()}
function renderProgress(){
 const total=state.locations.length,complete=state.locations.filter(i=>i.completed).length,verified=state.locations.filter(i=>i.verification==="Resynced verified").length,fav=state.locations.filter(i=>i.favorite).length;
 document.getElementById('metrics').innerHTML=`<div class="metric"><b>${complete}/${total}</b><span>Completed</span></div><div class="metric"><b>${Math.round(total?complete/total*100:0)}%</b><span>Overall</span></div><div class="metric"><b>${verified}</b><span>Resynced verified</span></div><div class="metric"><b>${fav}</b><span>Favorites</span></div>`;
 const make=(groups,el)=>{el.innerHTML='';Object.entries(groups).sort().forEach(([k,v])=>{const done=v.filter(i=>i.completed).length;el.innerHTML+=`<div class="progress-row"><div class="progress-label"><span>${esc(k)}</span><span>${done}/${v.length}</span></div><progress value="${done}" max="${v.length}"></progress></div>`})};
 const cats={};state.locations.forEach(i=>(cats[i.category]??=[]).push(i));make(cats,document.getElementById('categoryProgress'));
 const regs={};state.locations.forEach(i=>(regs[i.region]??=[]).push(i));make(regs,document.getElementById('regionProgress'));
}
function renderCalibration(){
 const el=document.getElementById('calibrationList');el.innerHTML=state.calibration.length?'':'<p style="color:var(--muted)">No points saved. Two well-separated points improve map alignment.</p>';
 state.calibration.forEach((p,n)=>{const d=document.createElement('div');d.className='location-row';d.innerHTML=`<strong>Point ${n+1}</strong><small>Image ${p.imageX.toFixed(3)}, ${p.imageY.toFixed(3)} → Game ${p.gameX}, ${p.gameY}</small>`;el.appendChild(d)})
}
function renderReports(){
 const el=document.getElementById('reportsList');el.innerHTML=state.corrections.length?'':'<p style="color:var(--muted)">No corrections saved.</p>';
 state.corrections.forEach(r=>{const i=state.locations.find(x=>x.id===r.locationID);el.innerHTML+=`<div class="location-row"><strong>${esc(i?.name||r.locationID)}</strong><small>${esc(r.summary)}<br>${r.oldX},${r.oldY} → ${r.newX},${r.newY}<br>${new Date(r.createdAt).toLocaleString()}</small></div>`})
}
function renderAll(){renderChips();renderMap();renderList();renderProgress();renderCalibration()}
function openEditor(id=null){
 editingID=id;const i=id?state.locations.find(x=>x.id===id):null;
 document.getElementById('editTitle').textContent=i?'Edit location':'Add location';
 const vals={fName:i?.name||'',fRegion:i?.region||'',fX:i?.gameX??'',fY:i?.gameY??'',fReward:i?.reward||'',fPrerequisite:i?.prerequisite||'',fInstructions:i?.instructions||'',fSourceTitle:i?.sourceTitle||'',fSourceURL:i?.sourceURL||''};
 Object.entries(vals).forEach(([k,v])=>document.getElementById(k).value=v);
 document.getElementById('fCategory').value=i?.category||CATEGORIES[0];document.getElementById('fVerification').value=i?.verification||VERIFICATIONS[2];document.getElementById('fAggregate').checked=!!i?.isAggregate;document.getElementById('fPhoto').value='';document.getElementById('deleteLocation').classList.toggle('hidden',!i);openModal('editModal')
}
async function saveEditor(){
 const name=document.getElementById('fName').value.trim(),x=Number(document.getElementById('fX').value),y=Number(document.getElementById('fY').value);if(!name||!Number.isFinite(x)||!Number.isFinite(y)){alert('Enter a name and valid coordinates.');return}
 let i=editingID?state.locations.find(x=>x.id===editingID):null;if(!i){i={id:'user-'+crypto.randomUUID(),completed:false,favorite:false,notes:'',customImageX:null,customImageY:null,photoData:null};state.locations.push(i)}
 Object.assign(i,{name,category:document.getElementById('fCategory').value,region:document.getElementById('fRegion').value,gameX:x,gameY:y,reward:document.getElementById('fReward').value,instructions:document.getElementById('fInstructions').value,prerequisite:document.getElementById('fPrerequisite').value,verification:document.getElementById('fVerification').value,sourceTitle:document.getElementById('fSourceTitle').value,sourceURL:document.getElementById('fSourceURL').value,isAggregate:document.getElementById('fAggregate').checked});
 const file=document.getElementById('fPhoto').files[0];if(file)i.photoData=await fileToDataURL(file);
 saveState();closeModal('editModal');renderAll()
}
function fileToDataURL(file){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsDataURL(file)})}
function openCorrection(id){correctionID=id;const i=state.locations.find(x=>x.id===id);document.getElementById('rSummary').value='';document.getElementById('rX').value=i.gameX;document.getElementById('rY').value=i.gameY;openModal('correctionModal')}
function downloadJSON(obj,name){const blob=new Blob([JSON.stringify(obj,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000)}
function setModeBanner(){
 const b=document.getElementById('modeBanner');
 if(markerEdit){b.textContent='Marker editing: drag a marker to reposition it and update its coordinates.';b.classList.remove('hidden')}
 else if(calibrationMode){b.textContent='Calibration: tap a known point on the picture, then enter its in-game coordinates.';b.classList.remove('hidden')}
 else b.classList.add('hidden')
}
document.querySelectorAll('.tab').forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active',v.id===b.dataset.view));if(b.dataset.view==='progressView')renderProgress()}));
document.getElementById('search').addEventListener('input',()=>{renderMap();renderList()});
['verifiedOnly','hideCompleted','favoritesOnly'].forEach(id=>document.getElementById(id).addEventListener('click',()=>{state.settings[id]=!state.settings[id];saveState();renderAll()}));
document.getElementById('editMarkers').addEventListener('click',()=>{markerEdit=!markerEdit;calibrationMode=false;document.getElementById('editMarkers').classList.toggle('active',markerEdit);document.getElementById('calibrate').classList.remove('active');setModeBanner();renderMap()});
document.getElementById('calibrate').addEventListener('click',()=>{calibrationMode=!calibrationMode;markerEdit=false;document.getElementById('calibrate').classList.toggle('active',calibrationMode);document.getElementById('editMarkers').classList.remove('active');setModeBanner();renderMap()});
document.getElementById('zoomIn').addEventListener('click',()=>zoom(1.3));document.getElementById('zoomOut').addEventListener('click',()=>zoom(.77));document.getElementById('resetMap').addEventListener('click',resetMap);
document.getElementById('fullMap').addEventListener('click',()=>document.getElementById('viewport').requestFullscreen?.());
document.getElementById('addLocation').addEventListener('click',()=>openEditor());
document.getElementById('saveLocation').addEventListener('click',saveEditor);
document.getElementById('deleteLocation').addEventListener('click',()=>{if(editingID&&confirm('Delete this location?')){state.locations=state.locations.filter(i=>i.id!==editingID);saveState();closeModal('editModal');renderAll()}});
document.getElementById('showCorrections').addEventListener('click',()=>{renderReports();openModal('reportsModal')});
document.getElementById('clearCalibration').addEventListener('click',()=>{if(confirm('Clear all calibration points?')){state.calibration=[];saveState();renderAll()}});
document.getElementById('resetData').addEventListener('click',()=>{if(confirm('Reset all progress, notes, edits, added locations and calibration?')){state=blankState();saveState();renderAll()}});
document.getElementById('saveCalibration').addEventListener('click',()=>{const gx=Number(document.getElementById('cGameX').value),gy=Number(document.getElementById('cGameY').value);if(!pendingCalibration||!Number.isFinite(gx)||!Number.isFinite(gy))return;state.calibration.push({id:crypto.randomUUID(),imageX:pendingCalibration.x,imageY:pendingCalibration.y,gameX:gx,gameY:gy});if(state.calibration.length>2)state.calibration=state.calibration.slice(-2);saveState();closeModal('calibrationModal');calibrationMode=false;document.getElementById('calibrate').classList.remove('active');setModeBanner();renderAll()});
document.getElementById('saveCorrection').addEventListener('click',()=>{const i=state.locations.find(x=>x.id===correctionID),nx=Number(document.getElementById('rX').value),ny=Number(document.getElementById('rY').value);if(!i||!Number.isFinite(nx)||!Number.isFinite(ny))return;state.corrections.push({id:crypto.randomUUID(),locationID:i.id,summary:document.getElementById('rSummary').value,createdAt:new Date().toISOString(),oldX:i.gameX,oldY:i.gameY,newX:nx,newY:ny});saveState();closeModal('correctionModal')});
document.getElementById('exportBackup').addEventListener('click',()=>downloadJSON(state,'BlackFlagCompanionBackup.json'));
document.getElementById('exportCorrections').addEventListener('click',()=>downloadJSON(state.corrections,'BlackFlagCorrections.json'));
document.getElementById('importBackup').addEventListener('change',async e=>{try{const parsed=JSON.parse(await e.target.files[0].text());if(!parsed.locations)throw new Error('Not a valid backup');state=parsed;saveState();renderAll();document.getElementById('backupMessage').textContent='Backup imported successfully.'}catch(err){document.getElementById('backupMessage').textContent='Import failed: '+err.message}});
const viewport=document.getElementById('viewport');
viewport.addEventListener('pointerdown',e=>{if(e.target.closest('.marker')||calibrationMode)return;viewport.setPointerCapture(e.pointerId);pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});dragStart={x:e.clientX,y:e.clientY,tx:transform.tx,ty:transform.ty}});
viewport.addEventListener('pointermove',e=>{if(!pointers.has(e.pointerId))return;pointers.set(e.pointerId,{x:e.clientX,y:e.clientY});const pts=[...pointers.values()];if(pts.length===2){const d=Math.hypot(pts[0].x-pts[1].x,pts[0].y-pts[1].y);if(lastDistance)zoom(d/lastDistance);lastDistance=d}else if(dragStart&&transform.scale>1){transform.tx=dragStart.tx+e.clientX-dragStart.x;transform.ty=dragStart.ty+e.clientY-dragStart.y;applyTransform()}});
function pointerEnd(e){pointers.delete(e.pointerId);if(pointers.size<2)lastDistance=0;if(!pointers.size)dragStart=null}
viewport.addEventListener('pointerup',pointerEnd);viewport.addEventListener('pointercancel',pointerEnd);
viewport.addEventListener('dblclick',e=>{const r=viewport.getBoundingClientRect();zoomAt((e.clientX-r.left-transform.tx)/(r.width*transform.scale),(e.clientY-r.top-transform.ty)/(r.height*transform.scale),transform.scale>1?1:2)});
viewport.addEventListener('click',e=>{if(!calibrationMode||e.target.closest('.marker')||e.target.closest('.map-toolbar'))return;const r=viewport.getBoundingClientRect();pendingCalibration={x:(e.clientX-r.left-transform.tx)/(r.width*transform.scale),y:(e.clientY-r.top-transform.ty)/(r.height*transform.scale)};document.getElementById('calibrationImagePoint').textContent=`Picture position: ${pendingCalibration.x.toFixed(3)}, ${pendingCalibration.y.toFixed(3)}`;document.getElementById('cGameX').value='';document.getElementById('cGameY').value='';openModal('calibrationModal')});
document.getElementById('headerIcon').src='data:image/png;base64,';
document.getElementById('mapImage').src='data:image/jpeg;base64,';
CATEGORIES.forEach(c=>{document.getElementById('fCategory').insertAdjacentHTML('beforeend',`<option>${c}</option>`)});
VERIFICATIONS.forEach(v=>{document.getElementById('fVerification').insertAdjacentHTML('beforeend',`<option>${v}</option>`)});
if('serviceWorker' in navigator&&location.protocol.startsWith('http'))navigator.serviceWorker.register('./service-worker.js').catch(()=>{});
renderAll();
